const raw = items[0].json;

let llmPayload = {};
if (raw?.message?.content !== undefined) {
  const c = raw.message.content;
  if (typeof c === 'string') {
    try {
      llmPayload = JSON.parse(c);
    } catch (e) {
      llmPayload = {};
    }
  } else {
    llmPayload = c || {};
  }
} else {
  llmPayload = raw || {};
}

const criteriaSource = $node["Set CriteriaArray"].json || {};
const baseCriteria = criteriaSource.criteria || [];

const requiredMap = {};
for (const c of baseCriteria) {
  if (!c || !c.id) continue;
  requiredMap[c.id] = c.required !== false;
}

const evalCriteria = Array.isArray(llmPayload.criteria) ? llmPayload.criteria : [];

let passedCount = 0;
let failedRequiredCount = 0;

for (const c of evalCriteria) {
  if (!c) continue;
  const score = Number(c.score) || 0;
  const required = requiredMap[c.id] ?? true;

  c.required = required;
  c.score = score;

  if (score === 1) passedCount++;
  if (required && score === 0) failedRequiredCount++;
}

const total = evalCriteria.length;

// тумблер переключения
// Активировать ветку Fail - 
const passed = failedRequiredCount === 0;

//const FORCE_SUCCESS_DEMO = true;  // ← ВРЕМЕННО, только чтобы проверить ветку успеха

//const passed = FORCE_SUCCESS_DEMO
//  ? true                      // форсируем успех для демонстрации
//  : failedRequiredCount === 0;
// меняется строка выше

const baseMeta = $node["Set InterviewContext"].json || {};

const attempt = Number(llmPayload.attempt ?? baseMeta.attempt ?? 1);
const maxAttempts = Number(llmPayload.maxAttempts ?? baseMeta.maxAttempts ?? 3);

return [
  {
    json: {
      candidateName: baseMeta.candidateName,
      telegramChatId: baseMeta.telegramChatId,
      maxAttempts,
      attempt,

      question: llmPayload.question,
      topic: llmPayload.topic,
      difficulty: llmPayload.difficulty,
      criteria: evalCriteria,

      validation: {
        passed,
        passedCount,
        failedRequiredCount,
        total,
      },
    },
  },
];

const item = items[0].json;

const currentAttempt = Number(item.attempt) || 1;
const maxAttempts = Number(item.maxAttempts) || 3;

const nextAttempt = currentAttempt + 1;

item.attempt = nextAttempt;
item.maxAttempts = maxAttempts;

// Краткий фидбек для следующего промпта
item.retryFeedback = `Предыдущий вопрос не прошёл критерии: 
passed=${item.validation?.passedCount}/${item.validation?.total}, 
failedRequired=${item.validation?.failedRequiredCount || 0}. 
Попробуй переформулировать вопрос лучше.`;

item.canRetry = nextAttempt <= maxAttempts;

return [{ json: item }];

